    document.addEventListener('DOMContentLoaded', function() {
      const interactionPart = document.getElementById('InteractionPart');
      const newsletterContainer = document.getElementById('newsletterContainer');
      const giftInput = document.getElementById('giftInput');

      interactionPart.addEventListener('click', function(e) {
        // Check if the click was not on the input itself
        if (e.target === giftInput) return;

        if (newsletterContainer.style.display === 'block') {
          newsletterContainer.style.display = 'none';
        } else {
          newsletterContainer.style.display = 'block';
          giftInput.focus();
        }
      });

      // Prevent clicks inside the container from closing it immediately
      newsletterContainer.addEventListener('click', function(e) {
        e.stopPropagation();
      });
    });
