    document.addEventListener('DOMContentLoaded', function() {
      const interactionElement = document.getElementById('InteractionPart');
      const dropdownItems = interactionElement.querySelectorAll('.dropdown-item, .dropdown-btn');

      dropdownItems.forEach(item => {
        item.addEventListener('click', function(e) {
          e.stopPropagation();
          const productName = interactionElement.querySelector('h4').textContent;
          const productPrice = interactionElement.querySelector('p').textContent;
          const action = this.textContent;

          if (this.textContent === 'Quick Buy') {
            alert(`Quick buy: ${productName} for ${productPrice}`);
          } else {
            console.log(`Action: ${action} - Product: ${productName} (${productPrice})`);
          }
        });
      });
    });
  </script>
